@startuml
title CrossoverOperators's Class Diagram

skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "Logic" {
  package "Operators" {
    package "CrossoverOperators" {

      enum CrossoverOperationType {
        COMPX
        MEAN
        MPX
        OPC
        TPC
        UC
        crossoverOperator
        text
      }

      abstract class CrossoverOperator << (A,#BFEFFF) >> {
        +generateChild()
        +isCompatible()
        +isSymmetric()
      }

      class CompositionCrossover << (C,#BFEFBF) >> {
        +generateChild()
        +isCompatible()
        +isSymmetric()
      }

      class MaximalPreservationCrossover << (C,#BFEFBF) >> {
        -rand : Random
        +generateChild()
        +isCompatible()
        +isSymmetric()
        +setSeed()
      }

      class OnePointCrossover << (C,#BFEFBF) >> {
        -RNG : Random
        +generateChild()
        +isCompatible()
        +isSymmetric()
        +setRandomSeed()
      }

      class UniformCrossover << (C,#BFEFBF) >> {
        -RNG : Random
        +generateChild()
        +isCompatible()
        +isSymmetric()
        +setRandomSeed()
      }

      class TwoPointCrossover << (C,#BFEFBF) >> {
        -RNG : Random
        +generateChild()
        +isCompatible()
        +isSymmetric()
        +setRandomSeed()
      }

      class OrdinalNumberMean << (C,#BFEFBF) >> {
        +OrdinalNumberMean()
        +generateChild()
        +isCompatible()
        +isSymmetric()
      }

      CrossoverOperationType o-- "crossoverOperator" CrossoverOperator

      CompositionCrossover -|> CrossoverOperator
      MaximalPreservationCrossover -|> CrossoverOperator
      OnePointCrossover -|> CrossoverOperator
      UniformCrossover -|> CrossoverOperator
      TwoPointCrossover -|> CrossoverOperator
      OrdinalNumberMean -|> CrossoverOperator

    }
  }
}
@enduml
